#!/usr/bin/env python3
"""Holocron AKB sync helper. Read-only source inspection; writes to Notion API."""
import json, os, re, sys, time, subprocess
from pathlib import Path

WORKSPACE = Path('/Users/ainchorsoc2a/.openclaw/workspace')
NOTION_KEY = *** / '.config' / 'notion' / 'api_key').read_text().strip()
API = 'https://api.notion.com/v1'
HEADERS = {'Authorization': f'Bearer {NOTION_KEY}', 'Notion-Version': '2022-06-28', 'Content-Type': 'application/json'}
HOL_ID = '39d890b6-ece8-8174-9fa2-c85f0ffa124c'
RATE = 0.35

def curl(method, path, payload=None):
    url = f'{API}{path}'
    cmd = ['curl', '-s', '-X', method, url, '-H', f'Authorization: Bearer {NOTION_KEY}', '-H', 'Notion-Version: 2022-06-28', '-H', 'Content-Type: application/json']
    if payload is not None:
        cmd += ['-d', json.dumps(payload)]
    for attempt in range(4):
        res = subprocess.run(cmd, capture_output=True, text=True)
        try:
            obj = json.loads(res.stdout)
        except Exception:
            obj = {'raw': res.stdout, 'err': res.stderr}
        if isinstance(obj, dict) and obj.get('status') == 429:
            wait = int(res.headers.get('Retry-After', 2)) if hasattr(res, 'headers') else 2
            time.sleep(wait)
            continue
        time.sleep(RATE)
        return obj
    return obj

def list_child_pages(parent_id):
    out = []
    nxt = f'/blocks/{parent_id}/children'
    while nxt:
        obj = curl('GET', nxt)
        for b in obj.get('results', []):
            if b['type'] == 'child_page':
                out.append({'id': b['id'], 'title': b['child_page']['title']})
        nxt = obj.get('next_cursor')
        if nxt:
            nxt = f'/blocks/{parent_id}/children?start_cursor={nxt}'
    return out

def find_page_by_title(parent_id, title):
    for p in list_child_pages(parent_id):
        if p['title'].strip().lower() == title.strip().lower():
            return p['id']
    return None

def create_child_page(parent_id, title):
    return curl('POST', '/pages', {'parent': {'page_id': parent_id}, 'properties': {'title': {'title': [{'text': {'content': title}}]}}})

def ensure_child_page(parent_id, title):
    pid = find_page_by_title(parent_id, title)
    if pid:
        return pid
    obj = create_child_page(parent_id, title)
    return obj.get('id')

def delete_all_blocks(page_id):
    # list and archive block children (Notion doesn't truly delete; archive)
    blocks = curl('GET', f'/blocks/{page_id}/children')
    for b in blocks.get('results', []):
        curl('DELETE', f'/blocks/{b["id"]}')

def append_blocks(page_id, blocks):
    # chunk 100 blocks per call
    for i in range(0, len(blocks), 100):
        chunk = blocks[i:i+100]
        curl('PATCH', f'/blocks/{page_id}/children', {'children': chunk})

def heading(level, text):
    typ = f'heading_{level}'
    return {typ: {'rich_text': [{'type': 'text', 'text': {'content': text}}]}}

def paragraph(text, bold=False):
    return {'paragraph': {'rich_text': [{'type': 'text', 'text': {'content': text}, 'annotations': {'bold': bold}}]}}

def bullet(text):
    return {'bulleted_list_item': {'rich_text': [{'type': 'text', 'text': {'content': text}}]}}

def divider():
    return {'divider': {}}

def main():
    print('Holocron pages:', list_child_pages(HOL_ID))
    print('Agent Fleet page:', ensure_child_page(HOL_ID, 'Agent Fleet'))

if __name__ == '__main__':
    main()
PYEOF
