#!/usr/bin/env python3
"""Build Agent Fleet content blocks from local AGENTS.md / SOUL.md / MEMORY.md."""
import json, re
from pathlib import Path
WORKSPACE = Path('/Users/ainchorsoc2a/.openclaw/workspace')

def read_agent_identity(agent_dir):
    soul = (WORKSPACE / agent_dir / 'SOUL.md').read_text() if (WORKSPACE / agent_dir / 'SOUL.md').exists() else ''
    agents = (WORKSPACE / agent_dir / 'AGENTS.md').read_text() if (WORKSPACE / agent_dir / 'AGENTS.md').exists() else ''
    return soul, agents

def extract_field(text, *patterns):
    for p in patterns:
        m = re.search(p, text, re.IGNORECASE)
        if m:
            return m.group(1).strip()
    return ''

def bullet(t): return {'bulleted_list_item': {'rich_text': [{'type':'text','text':{'content':t}}]}}
def heading(l,t): return {f'heading_{l}': {'rich_text': [{'type':'text','text':{'content':t}}]}}
def para(t,b=False): return {'paragraph': {'rich_text': [{'type':'text','text':{'content':t},'annotations':{'bold':b}}]}}
def divider(): return {'divider':{}}

def blocks_for_agent(name, agent_dir, emoji, runtime_id, reports, role):
    soul, agents = read_agent_identity(agent_dir)
    # derive fields
    role_txt = extract_field(soul, r'## Identity.*?Role:\s*(.+?)(?:\n|$)', r'Role:\s*(.+)') or role
    whatdo = extract_field(soul, r'## What I Do\s*\n(.+?)(?=\n##|\Z)', r'## Core Function\s*\n(.+?)(?=\n##|\Z)')
    hard = re.findall(r'-\s+(.+?)(?=\n|$)', re.search(r'## Hard Limits\s*\n(.+?)(?=\n##|\Z)', soul, re.S).group(1)) if re.search(r'## Hard Limits\s*\n(.+?)(?=\n##|\Z)', soul, re.S) else []
